import{_ as t,o as e,c as i,a1 as r}from"./chunks/framework.BwbI10pK.js";const d=JSON.parse('{"title":"JavaScript 深度","description":"","frontmatter":{},"headers":[],"relativePath":"javascript/index.md","filePath":"javascript/index.md"}'),o={name:"javascript/index.md"};function l(n,a,s,c,p,u){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="javascript-深度" tabindex="-1">JavaScript 深度 <a class="header-anchor" href="#javascript-深度" aria-label="Permalink to &quot;JavaScript 深度&quot;">​</a></h1><blockquote><p>副标题：从执行上下文到 V8 引擎，理解代码在运行时真实发生的每一件事</p></blockquote><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>JavaScript 是前端工程师每天使用的语言，但&quot;会用&quot;和&quot;理解&quot;之间隔着一条巨大的鸿沟。本模块不停留在语法层面，而是深入 V8 引擎的执行机制：执行上下文如何创建、作用域链如何形成、闭包在内存中如何存续、异步任务如何在事件循环中调度、JIT 如何优化热点代码、GC 如何回收内存。</p><p>理解这些底层机制，才能写出可预测性能的代码，才能在排查闭包泄漏、内存暴涨、长任务卡顿等问题时知道从哪里下手。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><ul><li><strong>执行机制</strong>：执行上下文、作用域链、变量环境、词法环境与闭包本质</li><li><strong>异步编程</strong>：事件循环、宏任务与微任务、Promise 链、async/await 的演进与陷阱</li><li><strong>V8 引擎</strong>：Ignition 字节码、Sparkplug / Maglev / TurboFan JIT 层级、对象 shape 与隐藏类</li><li><strong>内存管理</strong>：新生代 / 老生代 GC、Scavenge 与 Mark-Sweep-Compact、短命对象与内存泄漏</li><li><strong>性能边界</strong>：JIT 去优化、GC 暂停、长任务拆分与主线程调度</li></ul><h2 id="文章导览" tabindex="-1">文章导览 <a class="header-anchor" href="#文章导览" aria-label="Permalink to &quot;文章导览&quot;">​</a></h2><ul><li><a href="/javascript/execution-context-closure">执行上下文与作用域链：从 V8 视角理解闭包本质</a> — 闭包不是语法糖，而是词法环境的引用持有</li><li><a href="/javascript/async-evolution">异步编程的演进：从回调地狱到 async/await</a> — Promise / Generator / async/await 的设计脉络与陷阱</li><li><a href="/javascript/v8-jit-gc">V8 引擎揭秘：JIT 编译与垃圾回收机制</a> — 从字节码到 TurboFan，从 Scavenge 到 Mark-Compact</li></ul><h2 id="适用读者" tabindex="-1">适用读者 <a class="header-anchor" href="#适用读者" aria-label="Permalink to &quot;适用读者&quot;">​</a></h2><ul><li>中高级前端工程师，希望理解 JavaScript 运行时行为而非仅停留在语法层</li><li>性能优化工程师，需要排查内存泄漏、长任务、JIT 去优化等问题</li><li>框架开发者，需要评估不同 API 的运行时成本与 GC 压力</li></ul>',11)])])}const _=t(o,[["render",l]]);export{d as __pageData,_ as default};
